  const workload=state.team.filter(t=>t.active).map(t=>{const jobs=rows.filter(b=>b.assignedPicker===t.name&&b.collectionStatus!=='Collected');return `<section class="workload-person"><div class="workload-head"><strong>${safe(t.name)}</strong><span>${jobs.length} active</span></div>${jobs.length?jobs.sort(sortTime).map(b=>`<button class="workload-order" data-id="${b.id}"><span>${safe(b.collectionTime||'Anytime')}</span><b>${safe(b.orderNumber)}</b><small>${safe(b.customer)}</small>${statusPill(b)}</button>`).join(''):'<p class="workload-empty">No active orders assigned</p>'}</section>`}).join('');
  $('pageBody').innerHTML=`<div class="dashboard-metrics dashboard-metrics-compact"><div class="dashboard-card"><span>Today’s bookings</span><strong>${rows.length}</strong></div><div class="dashboard-card"><span>Collected</span><strong>${collected.length}</strong></div><div class="dashboard-card"><span>Average wait time</span><strong>${avgMinutes(collected,'customerWaitingAt','collectedAt')} min</strong></div><div class="dashboard-card"><span>Average pick time</span><strong>${avgMinutes(rows,'pickingStartedAt','readyAt')} min</strong></div></div><div class="dashboard-layout"><section class="dashboard-panel queue-panel"><h3>Today’s Queue</h3>${queue('Advance Picks',large)}${queue('Small Orders / Walk-ins',small)}</section><section class="dashboard-panel waiting-panel"><h3>Customer Waiting</h3>${waiting.map(b=>`<button class="waiting-row" data-id="${b.id}"><span><b>${safe(b.orderNumber)}</b><small>${safe(b.customer)}</small></span><span class="waiting-flags">${typePill(b)}${statusPill(b)}</span></button>`).join('')||empty('No customers waiting','Customers marked waiting will appear here.')}</section><section class="dashboard-panel workload-panel"><h3>Team Workload</h3><div class="workload-list">${workload}</div></section></div>`;
  document.querySelectorAll('[data-id]').forEach(x=>x.onclick=()=>openOrder(x.dataset.id));
