function wireCards(){
  document.querySelectorAll('.booking-card').forEach(el=>{
    el.onclick=()=>openOrder(el.dataset.id);
    el.ondragstart=e=>{e.stopPropagation();e.dataTransfer.effectAllowed='move';e.dataTransfer.setData('text/plain',el.dataset.id);requestAnimationFrame(()=>el.classList.add('is-moving'))};
    el.ondragend=()=>el.classList.remove('is-moving');
  });
  document.querySelectorAll('.slot:not(.blocked),.day-column,.board-list').forEach(el=>{
    el.ondragover=e=>{e.preventDefault();e.dataTransfer.dropEffect='move';el.classList.add('drag-over')};
    el.ondragleave=e=>{if(!el.contains(e.relatedTarget))el.classList.remove('drag-over')};
    el.ondrop=e=>{e.preventDefault();e.stopPropagation();el.classList.remove('drag-over');const id=e.dataTransfer.getData('text/plain');if(!id)return;const changes=el.dataset.status?{pickStatus:el.dataset.status,source:'Drag and drop'}:el.dataset.time?{collectionDate:el.dataset.date,collectionTime:el.dataset.time,source:'Drag and drop'}:{collectionDate:el.dataset.date,source:'Drag and drop'};quickUpdate(id,changes)};
  });
}
async function quickUpdate(id,changes){
  const current=state.bookings.find(b=>b.id===id)||state.selected||state.searchResults.find(b=>b.id===id)||state.operationalResults.find(b=>b.id===id);if(!current)return toast('The booking is not available in the current view. Refresh and try again.','error');
  const snapshot=JSON.parse(JSON.stringify(current)),expectedVersion=Number(current.version||0);Object.assign(current,changes);if(state.selected?.id===id)Object.assign(state.selected,changes);renderCurrent();state.saveBusy=true;setLoading(true,'Saving changes…');
  try{const payload={...changes,expectedVersion};const r=await api('quick',{id,changes:JSON.stringify(payload)});const saved=r.booking||current;Object.assign(current,saved);if(state.selected?.id===id)state.selected=current;state.revision=String(r.revision??state.revision);state.activityCache.delete(id);toast('Changes saved');renderCurrent();if(state.selected?.id===id){const active=document.querySelector('[data-order-tab].active')?.dataset.orderTab||'details';renderOrderTab(active)}}
  catch(err){Object.keys(current).forEach(k=>delete current[k]);Object.assign(current,snapshot);if(state.selected?.id===id)state.selected=current;renderCurrent();if(/changed|updated|version|refresh/i.test(err.message)){state.deferredSync=true;alert(err.message+'\n\nYour change was not saved. The latest version will now be loaded.');await fetchBookings({visible:true,force:true})}else toast(err.message,'error')}
  finally{state.saveBusy=false;setLoading(false)}
}
async function openOrder(id){let b=state.bookings.find(x=>x.id===id)||state.searchResults.find(x=>x.id===id)||state.operationalResults.find(x=>x.id===id);if(!b)return;state.selected=b;state.viewingOrderId=b.id;state.viewingOrderNumber=b.orderNumber;$('orderPanel').classList.remove('hidden');renderOrderTab('details');heartbeat()}
function renderOrderViewers(){const el=$('orderViewers');if(!el)return;const viewers=state.presence.filter(x=>x.viewingOrderId===state.viewingOrderId&&x.name!==state.user?.name);el.innerHTML=viewers.length?`<span class="viewer-dot"></span>${viewers.map(x=>safe(x.name)).join(', ')} also viewing`:'';el.classList.toggle('hidden',!viewers.length)}
function showOrderConflict(fresh){const el=$('orderConflict');if(!el)return;el.classList.remove('hidden');el.innerHTML=`<strong>Newer changes are available</strong><span>${safe(fresh.lastModifiedBy||'Another user')} updated this order. Finish or close your current work, then reload the latest version.</span><button id="reloadOrderVersion">Reload latest</button>`;setTimeout(()=>{const b=$('reloadOrderVersion');if(b)b.onclick=()=>{state.selected=fresh;state.deferredSync=false;el.classList.add('hidden');renderOrderTab('details')}},0)}
function statusPills(b){const out=[];if(b.collectionStatus==='Customer Waiting')out.push('<span class="pill held">Customer Waiting</span>');if(b.collectionStatus==='Collected')out.push('<span class="pill ready">Collected</span>');else out.push(`<span class="pill status ${String(b.pickStatus||'Waiting').toLowerCase()}">${safe(b.pickStatus||'Waiting')}</span>`);return out.join(' ')}
function trackerDone(b,i){if(i===0)return true;if(i===1)return ['Picking','Ready'].includes(b.pickStatus)||b.collectionStatus==='Collected';if(i===2)return b.pickStatus==='Ready'||b.collectionStatus==='Collected';return b.collectionStatus==='Collected'}
function detail(k,v){return `<div class="summary-row"><span>${safe(k)}</span><strong>${safe(v)}</strong></div>`}
function money(v){return `£${Number(v||0).toFixed(2)}`}
function parsePayments(b){try{return Array.isArray(b.paymentLogs)?b.paymentLogs:JSON.parse(b.paymentLogs||'[]')}catch{return []}}
function paymentTotal(b){return parsePayments(b).reduce((n,x)=>n+Number(x.amount||0),0)}
function paymentSummary(b){const logs=parsePayments(b);return logs.length?`${money(paymentTotal(b))} logged · ${logs.length} payment${logs.length===1?'':'s'}`:'No payments logged'}
