  b.itemCount=Number(b.itemCount||0);b.orderValue=Number(b.orderValue||0);b.paymentLogs=state.editing?parsePayments(state.editing):[];b.paymentConfirmed=!!state.editing?.paymentConfirmed;b.paymentConfirmedAt=state.editing?.paymentConfirmedAt||'';
